import React, { Suspense } from 'react'
import { useTranslation } from 'react-i18next'
import { css } from '@linaria/core'
import {
  DialogOverlayActions,
  DialogOverlay,
  DialogOverlayFooter,
  Button,
  Radio,
  Paragraph,
  DataBlock,
  Select,
  useContainerWidth,
  Ellipsis,
} from '@fs/zion-ui'
import { NoticeLoading } from '@fs/zion-icon'
import { usePlaceTypeSuggest } from '@fs/zion-standards'
import HelpButton from '../HelpButton/HelpButton'

const placeTypeRadioGroupCss = css`
  display: grid;
  grid-column-gap: 20px;
  grid-template-columns: repeat(auto-fit, minmax(120px, 1fr));
`

function getSelectedValue({ selected, placeSuggestTypes }) {
  if (selected && placeSuggestTypes) {
    const index = placeSuggestTypes.findIndex((t) => t.id === selected.id)
    if (index !== -1) {
      return index
    }
  }
  return undefined
}

export default function SelectPlaceType({ selected, onCancel, onNext, onChange, title, subtitle, overlay }) {
  const [t] = useTranslation()
  const atWidth = useContainerWidth()
  const { suggestions } = usePlaceTypeSuggest({ includePlaceTypes: false, includePPFTypes: true })
  const handleChange = (e) => {
    const newIndex = e.target.value
    onChange(suggestions[newIndex])
  }
  const selectOptions = suggestions.map((type, index) => {
    return { value: String(index), label: type.primaryText }
  })

  const value = getSelectedValue({ selected, placeSuggestTypes: suggestions })

  return (
    <DialogOverlay title={title} subtitle={subtitle} {...overlay} closeOnClickAway={false}>
      <Suspense fallback={<NoticeLoading />}>
        <div style={{ height: 'inherit' }}>
          <Paragraph>
            {t(
              'provisional-place.select-place-type.text',
              'The following place types are a set of geographical areas and structures that may be submitted. Larger parent places cannot be added, such as county, country, province, region, or state.'
            )}
          </Paragraph>
          {atWidth({
            default: (
              <Select
                label={t('provisional-place.place-type.label', 'Place Type')}
                name="selectPlaceType"
                value={String(value)}
                placeholder={t('provisional-place.select-place-type.heading', 'Select a Category')}
                options={selectOptions}
                onChange={handleChange}
              />
            ),
            sm: (
              <div className={placeTypeRadioGroupCss}>
                {suggestions.map((s, index) => {
                  return (
                    <Radio
                      key={s.key}
                      checked={selected?.id === s.id}
                      label={
                        <div style={{ maxWidth: 130 }}>
                          <Ellipsis>{s.primaryText || ''}</Ellipsis>
                        </div>
                      }
                      name={`option-${index}`}
                      value={`${index}`}
                      onChange={handleChange}
                    />
                  )
                })}
              </div>
            ),
          })}

          {selected && <DataBlock heading={selected?.primaryText || ''} data={selected?.secondaryText || ''} />}
        </div>
      </Suspense>
      <DialogOverlayFooter>
        <DialogOverlayActions>
          <HelpButton />
          <Button emphasis="medium" onClick={onCancel}>
            {t('common-ui:cancel.action', 'Cancel')}
          </Button>
          <Button type="submit" emphasis="high" onClick={onNext} disabled={!selected}>
            {t('common-ui:next.action', 'Next')}
          </Button>
        </DialogOverlayActions>
      </DialogOverlayFooter>
    </DialogOverlay>
  )
}
